// Mapeia eventos do GHL para eventos Meta CAPI
const body = $input.item.json.body || $input.item.json;

// Extrair dados do payload GHL
const locationId = body.location_id || body.locationId || body.location?.id || '';
const contactId = body.contact_id || body.contactId || body.contact?.id || '';
const email = body.email || body.contact?.email || '';
const phone = body.phone || body.contact?.phone || '';
const firstName = body.first_name || body.firstName || body.contact?.firstName || '';
const lastName = body.last_name || body.lastName || body.contact?.lastName || '';
const monetaryValue = body.monetary_value || body.monetaryValue || body.opportunity?.monetaryValue || 0;

// Detectar tipo de evento
const eventType = body.type || body.event_type || '';
const pipelineStage = body.pipeline_stage || body.pipelineStage || body.opportunity?.pipelineStageId || '';
const stageName = body.stage_name || body.stageName || body.opportunity?.stageName || '';

let eventName = null;
let customData = {};

// Mapeamento de eventos
if (stageName === 'Qualificado' || pipelineStage === 'Qualificado') {
  eventName = 'LeadQualified';
  customData = { stage: 'Qualificado' };
} else if (eventType === 'appointment.booked' || eventType === 'AppointmentBooked') {
  eventName = 'Schedule';
  customData = {
    appointment_id: body.appointment_id || body.appointmentId || '',
    calendar_id: body.calendar_id || body.calendarId || ''
  };
} else if (eventType === 'appointment.attended' || eventType === 'appointment.completed' || eventType === 'AppointmentAttended') {
  eventName = 'CompleteRegistration';
  customData = {
    appointment_id: body.appointment_id || body.appointmentId || '',
    status: 'attended'
  };
} else if (eventType === 'opportunity.won' || eventType === 'OpportunityWon' || stageName === 'Won') {
  eventName = 'Purchase';
  customData = {
    currency: 'BRL',
    value: parseFloat(monetaryValue) || 0
  };
}

// Se nao mapeou nenhum evento, retornar sem processar
if (!eventName) {
  return {
    skip: true,
    reason: 'Event type not mapped: ' + eventType + ' | stage: ' + stageName,
    locationId,
    contactId
  };
}

return {
  skip: false,
  eventName,
  locationId,
  contactId,
  email,
  phone,
  firstName,
  lastName,
  customData,
  rawPayload: body
};

const crypto = require('crypto');

// Funcao de hash SHA-256
const hashValue = (val) => {
  if (!val) return null;
  return crypto.createHash('sha256').update(val.trim().toLowerCase()).digest('hex');
};

// Dados do evento (vem do Identify Event)
const identifyData = $('Identify Event').first().json;

// Dados do dataset config
const datasetConfig = $('Fetch Dataset Config').first().json;

// Montar user_data com hash
const userData = {};

if (identifyData.email) {
  userData.em = [hashValue(identifyData.email)];
}

if (identifyData.phone) {
  const phoneClean = identifyData.phone.replace(/\D/g, '');
  userData.ph = [hashValue(phoneClean)];
}

if (identifyData.firstName) {
  userData.fn = [hashValue(identifyData.firstName)];
}

if (identifyData.lastName) {
  userData.ln = [hashValue(identifyData.lastName)];
}

// Gerar event dedup ID
const eventId = crypto.createHash('sha256')
  .update(identifyData.contactId + '_' + identifyData.eventName + '_' + Date.now().toString())
  .digest('hex')
  .substring(0, 32);

return {
  eventName: identifyData.eventName,
  eventTime: Math.floor(Date.now() / 1000),
  eventId,
  userData,
  customData: identifyData.customData || {},
  datasetId: datasetConfig.meta_dataset_id,
  accessToken: datasetConfig.meta_capi_access_token,
  locationId: identifyData.locationId,
  contactId: identifyData.contactId
};
